import React, { useState, useEffect } from 'react';
import {
  Box,
  Card,
  CardContent,
  Grid,
  Button,
  Typography,
  IconButton,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  Chip,
  Stack,
  Alert,
  Snackbar,
  LinearProgress,
  CircularProgress,
  useTheme,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Divider
} from '@mui/material';
import {
  Add as AddIcon,
  Edit as EditIcon,
  Delete as DeleteIcon,
  DarkMode as DarkModeIcon,
  LightMode as LightModeIcon,
  OpenInNew as OpenInNewIcon,
  Refresh as RefreshIcon,
  FolderOpen as FolderIcon
} from '@mui/icons-material';
import { motion } from 'framer-motion';
import { 
  getNodes, 
  getNodeStatus, 
  updateNode, 
  deleteNode 
} from '../services/api';

const Nodes = ({ mode, setMode, onDashboardClick }) => {
  const theme = useTheme();
  const [nodes, setNodes] = useState([]);
  const [nodeGroups, setNodeGroups] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(false);
  const [openDialog, setOpenDialog] = useState(false);
  const [selectedNode, setSelectedNode] = useState(null);
  const [editNode, setEditNode] = useState({
    name: '',
    type: 'select',
    region: '',
    subscription: '',
    excludes: [],
    includes: []
  });

  useEffect(() => {
    fetchNodes();
    fetchNodeGroups();
  }, []);

  const fetchNodes = async () => {
    try {
      setLoading(true);
      const data = await getNodes();
      setNodes(data);
    } catch (err) {
      setError('Failed to load nodes');
    } finally {
      setLoading(false);
    }
  };

  const fetchNodeGroups = async () => {
    try {
      // 模拟节点分组数据，实际应该从API获取
      const groups = [
        { id: 1, name: '香港节点', count: 5, type: 'HK', status: 'active' },
        { id: 2, name: '日本节点', count: 3, type: 'JP', status: 'active' },
        { id: 3, name: '新加坡节点', count: 4, type: 'SG', status: 'active' },
        { id: 4, name: '美国节点', count: 6, type: 'US', status: 'active' },
      ];
      setNodeGroups(groups);
    } catch (err) {
      setError('Failed to load node groups');
    }
  };

  const handleOpenDialog = (node = null) => {
    if (node) {
      setSelectedNode(node);
      setEditNode(node);
    } else {
      setSelectedNode(null);
      setEditNode({
        name: '',
        type: 'select',
        region: '',
        subscription: '',
        excludes: [],
        includes: []
      });
    }
    setOpenDialog(true);
  };

  const handleCloseDialog = () => {
    setOpenDialog(false);
    setSelectedNode(null);
    setEditNode({
      name: '',
      type: 'select',
      region: '',
      subscription: '',
      excludes: [],
      includes: []
    });
  };

  const handleSave = async () => {
    try {
      setLoading(true);
      if (selectedNode) {
        await updateNode(selectedNode.id, editNode);
      }
      await fetchNodes();
      setSuccess(true);
      handleCloseDialog();
    } catch (err) {
      setError('Failed to save node');
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    try {
      setLoading(true);
      await deleteNode(id);
      await fetchNodes();
      setSuccess(true);
    } catch (err) {
      setError('Failed to delete node');
    } finally {
      setLoading(false);
    }
  };

  const handleRefresh = async (id) => {
    try {
      setLoading(true);
      await getNodeStatus(id);
      await fetchNodes();
      setSuccess(true);
    } catch (err) {
      setError('Failed to refresh node status');
    } finally {
      setLoading(false);
    }
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'running':
        return 'success';
      case 'stopped':
        return 'error';
      case 'warning':
        return 'warning';
      default:
        return 'default';
    }
  };

  const cardStyle = {
    height: '100%',
    transition: 'all 0.2s ease-in-out',
    background: theme.palette.mode === 'dark' 
      ? 'linear-gradient(145deg, rgba(26,35,126,0.7), rgba(49,27,146,0.7))'
      : 'linear-gradient(145deg, rgba(255,255,255,0.9), rgba(255,255,255,0.95))',
    backdropFilter: 'blur(10px)',
    border: theme.palette.mode === 'dark'
      ? '1px solid rgba(255,255,255,0.1)'
      : '1px solid rgba(255,255,255,0.5)',
    boxShadow: theme.palette.mode === 'dark'
      ? '0 4px 12px 0 rgba(0,0,0,0.3), 0 2px 4px -1px rgba(0,0,0,0.4)'
      : '0 4px 12px 0 rgba(31,38,135,0.15), 0 2px 4px -1px rgba(31,38,135,0.2)',
    '&:hover': {
      transform: 'translateY(-2px)',
      boxShadow: theme.palette.mode === 'dark'
        ? '0 6px 16px 0 rgba(0,0,0,0.4), 0 3px 6px -2px rgba(0,0,0,0.5)'
        : '0 6px 16px 0 rgba(31,38,135,0.25), 0 3px 6px -2px rgba(31,38,135,0.3)',
    }
  };

  const headerCardStyle = {
    background: theme.palette.mode === 'dark' 
      ? 'linear-gradient(90deg, #1a237e 0%, #311b92 100%)'
      : 'linear-gradient(90deg, #3949ab 0%, #5e35b1 100%)',
    color: '#fff',
    boxShadow: theme.palette.mode === 'dark'
      ? '0 4px 12px 0 rgba(0,0,0,0.3), 0 2px 4px -1px rgba(0,0,0,0.4)'
      : '0 4px 12px 0 rgba(31,38,135,0.15), 0 2px 4px -1px rgba(31,38,135,0.2)',
    mb: 1.5,
    backdropFilter: 'blur(10px)',
    border: '1px solid rgba(255,255,255,0.1)',
  };

  const cardVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: { 
      opacity: 1, 
      y: 0,
      transition: {
        duration: 0.3,
      }
    }
  };

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.1
      }
    }
  };

  return (
    <Box>
      <Snackbar 
        open={success} 
        autoHideDuration={3000} 
        onClose={() => setSuccess(false)}
      >
        <Alert severity="success">操作成功</Alert>
      </Snackbar>

      <Snackbar 
        open={!!error} 
        autoHideDuration={3000} 
        onClose={() => setError(null)}
      >
        <Alert severity="error">{error}</Alert>
      </Snackbar>

      <Card sx={headerCardStyle}>
        <CardContent sx={{ py: 1.5, px: 2, '&:last-child': { pb: 1.5 } }}>
          <Stack direction="row" alignItems="center" justifyContent="space-between">
            <Stack direction="row" alignItems="center" spacing={2}>
              <Typography variant="h5" sx={{ fontWeight: 500, color: 'inherit' }}>
                节点管理
              </Typography>
              {loading && (
                <Box sx={{ display: 'flex', alignItems: 'center' }}>
                  <CircularProgress size={20} thickness={4} sx={{ color: 'rgba(255,255,255,0.8)' }} />
                </Box>
              )}
            </Stack>
            <Stack direction="row" spacing={1}>
              <IconButton
                size="small"
                onClick={onDashboardClick}
                sx={{ 
                  color: 'rgba(255,255,255,0.8)',
                  '&:hover': { 
                    color: '#fff',
                    backgroundColor: 'rgba(255,255,255,0.1)' 
                  }
                }}
              >
                <OpenInNewIcon fontSize="small" />
              </IconButton>
              <IconButton
                size="small"
                onClick={() => setMode(mode === 'dark' ? 'light' : 'dark')}
                sx={{ 
                  color: 'rgba(255,255,255,0.8)',
                  '&:hover': { 
                    color: '#fff',
                    backgroundColor: 'rgba(255,255,255,0.1)' 
                  }
                }}
              >
                {mode === 'dark' ? <LightModeIcon fontSize="small" /> : <DarkModeIcon fontSize="small" />}
              </IconButton>
            </Stack>
          </Stack>
        </CardContent>
      </Card>

      {loading && <LinearProgress sx={{ mb: 1 }} />}

      <Box sx={{ mb: 2, display: 'flex', justifyContent: 'flex-end', gap: 1 }}>
        <Button
          variant="contained"
          size="small"
          startIcon={<RefreshIcon />}
          onClick={fetchNodes}
          disabled={loading}
          sx={{
            borderRadius: 2,
            px: 3,
            background: theme.palette.mode === 'dark' 
              ? 'linear-gradient(45deg, #1a237e 30%, #311b92 90%)'
              : 'linear-gradient(45deg, #3949ab 30%, #5e35b1 90%)',
            boxShadow: theme.palette.mode === 'dark'
              ? '0 3px 8px 0 rgba(0,0,0,0.4)'
              : '0 3px 8px 0 rgba(31,38,135,0.2)',
            '&:hover': {
              background: theme.palette.mode === 'dark' 
                ? 'linear-gradient(45deg, #1a237e 20%, #311b92 100%)'
                : 'linear-gradient(45deg, #3949ab 20%, #5e35b1 100%)',
              boxShadow: theme.palette.mode === 'dark'
                ? '0 4px 10px 0 rgba(0,0,0,0.5)'
                : '0 4px 10px 0 rgba(31,38,135,0.3)',
            },
          }}
        >
          刷新节点
        </Button>
        <Button
          variant="contained"
          size="small"
          startIcon={<AddIcon />}
          onClick={() => handleOpenDialog()}
          sx={{
            borderRadius: 2,
            px: 3,
            background: theme.palette.mode === 'dark' 
              ? 'linear-gradient(45deg, #1a237e 30%, #311b92 90%)'
              : 'linear-gradient(45deg, #3949ab 30%, #5e35b1 90%)',
            boxShadow: theme.palette.mode === 'dark'
              ? '0 3px 8px 0 rgba(0,0,0,0.4)'
              : '0 3px 8px 0 rgba(31,38,135,0.2)',
            '&:hover': {
              background: theme.palette.mode === 'dark' 
                ? 'linear-gradient(45deg, #1a237e 20%, #311b92 100%)'
                : 'linear-gradient(45deg, #3949ab 20%, #5e35b1 100%)',
              boxShadow: theme.palette.mode === 'dark'
                ? '0 4px 10px 0 rgba(0,0,0,0.5)'
                : '0 4px 10px 0 rgba(31,38,135,0.3)',
            },
          }}
        >
          添加节点
        </Button>
      </Box>

      <motion.div
        variants={containerVariants}
        initial="hidden"
        animate="visible"
      >
        {/* 节点列表 */}
        <Card sx={{ ...cardStyle, mb: 3 }}>
          <CardContent sx={{ p: '16px !important' }}>
            <Typography variant="h6" sx={{ mb: 2, display: 'flex', alignItems: 'center', gap: 1 }}>
              节点列表
            </Typography>
            <TableContainer component={Paper} sx={{ 
              boxShadow: 'none',
              background: 'transparent',
              '& .MuiTableCell-root': {
                borderColor: theme.palette.mode === 'dark' 
                  ? 'rgba(255, 255, 255, 0.1)'
                  : 'rgba(0, 0, 0, 0.1)',
              }
            }}>
              <Table sx={{ minWidth: 650 }} size="small">
                <TableHead>
                  <TableRow>
                    <TableCell>节点名称</TableCell>
                    <TableCell align="center">类型</TableCell>
                    <TableCell align="center">状态</TableCell>
                    <TableCell align="center">延迟</TableCell>
                    <TableCell align="right">操作</TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {nodes.map((node) => (
                    <TableRow key={node.id}>
                      <TableCell component="th" scope="row">
                        {node.name}
                      </TableCell>
                      <TableCell align="center">
                        <Chip 
                          label={node.type} 
                          color="primary" 
                          size="small"
                          sx={{
                            borderRadius: 1,
                            '& .MuiChip-label': {
                              px: 1,
                            },
                          }}
                        />
                      </TableCell>
                      <TableCell align="center">
                        <Chip 
                          label={node.status ? "在线" : "离线"} 
                          color={node.status ? "success" : "error"} 
                          size="small"
                          sx={{
                            borderRadius: 1,
                            '& .MuiChip-label': {
                              px: 1,
                            },
                          }}
                        />
                      </TableCell>
                      <TableCell align="center">
                        <Typography 
                          variant="body2"
                          sx={{
                            color: node.latency < 100 ? 'success.main' : 
                                   node.latency < 200 ? 'warning.main' : 'error.main'
                          }}
                        >
                          {node.latency}ms
                        </Typography>
                      </TableCell>
                      <TableCell align="right">
                        <Stack direction="row" spacing={1} justifyContent="flex-end">
                          <IconButton 
                            size="small"
                            onClick={() => handleOpenDialog(node)}
                            sx={{
                              color: 'text.secondary',
                              '&:hover': {
                                color: 'primary.main',
                                backgroundColor: 'action.hover',
                              },
                            }}
                          >
                            <EditIcon fontSize="small" />
                          </IconButton>
                          <IconButton 
                            size="small"
                            onClick={() => handleDelete(node.id)}
                            sx={{
                              color: 'text.secondary',
                              '&:hover': {
                                color: 'error.main',
                                backgroundColor: 'action.hover',
                              },
                            }}
                          >
                            <DeleteIcon fontSize="small" />
                          </IconButton>
                        </Stack>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </TableContainer>
          </CardContent>
        </Card>

        {/* 节点分组 */}
        <Box sx={{ mb: 2 }}>
          <Typography variant="h6" sx={{ mb: 2, display: 'flex', alignItems: 'center', gap: 1 }}>
            <FolderIcon sx={{ fontSize: '1.2rem' }} />
            节点分组
          </Typography>
          <Grid container spacing={2}>
            {nodeGroups.map((group) => (
              <Grid item xs={12} sm={6} md={3} key={group.id}>
                <motion.div variants={cardVariants}>
                  <Card sx={cardStyle}>
                    <CardContent sx={{ p: '16px !important' }}>
                      <Stack spacing={2}>
                        <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                          <Typography variant="h6">{group.name}</Typography>
                          <Chip 
                            label={`${group.count} 个节点`}
                            size="small"
                            color="primary"
                            sx={{
                              borderRadius: 1,
                              background: theme.palette.mode === 'dark' 
                                ? 'rgba(144, 202, 249, 0.2)'
                                : 'rgba(25, 118, 210, 0.1)',
                              color: theme.palette.mode === 'dark'
                                ? '#90caf9'
                                : theme.palette.primary.main,
                            }}
                          />
                        </Box>
                        <Stack direction="row" spacing={1}>
                          <Chip 
                            label={group.type} 
                            size="small"
                            sx={{
                              borderRadius: 1,
                              background: theme.palette.mode === 'dark' 
                                ? 'rgba(144, 202, 249, 0.1)'
                                : 'rgba(25, 118, 210, 0.05)',
                              color: theme.palette.mode === 'dark'
                                ? '#90caf9'
                                : theme.palette.primary.main,
                            }}
                          />
                          <Chip 
                            label={group.status === 'active' ? '活跃' : '不活跃'} 
                            size="small"
                            sx={{
                              borderRadius: 1,
                              background: group.status === 'active'
                                ? theme.palette.mode === 'dark'
                                  ? 'rgba(76, 175, 80, 0.2)'
                                  : 'rgba(76, 175, 80, 0.1)'
                                : theme.palette.mode === 'dark'
                                  ? 'rgba(244, 67, 54, 0.2)'
                                  : 'rgba(244, 67, 54, 0.1)',
                              color: group.status === 'active'
                                ? theme.palette.success.main
                                : theme.palette.error.main,
                            }}
                          />
                        </Stack>
                      </Stack>
                    </CardContent>
                  </Card>
                </motion.div>
              </Grid>
            ))}
          </Grid>
        </Box>
      </motion.div>

      <Dialog 
        open={openDialog} 
        onClose={handleCloseDialog} 
        maxWidth="sm" 
        fullWidth
        PaperProps={{
          sx: {
            borderRadius: 2,
            boxShadow: theme.palette.mode === 'dark'
              ? '0 8px 24px 0 rgba(0,0,0,0.4)'
              : '0 8px 24px 0 rgba(31,38,135,0.2)',
          }
        }}
      >
        <DialogTitle>
          {selectedNode ? '编辑节点' : '添加节点'}
        </DialogTitle>
        <DialogContent>
          <Box sx={{ pt: 2 }}>
            <Grid container spacing={2}>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="节点名称"
                  value={editNode.name}
                  onChange={(e) => setEditNode({ ...editNode, name: e.target.value })}
                  size="small"
                  sx={{
                    '& .MuiOutlinedInput-root': {
                      '&:hover fieldset': {
                        borderColor: 'primary.main',
                      },
                    },
                  }}
                />
              </Grid>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="节点类型"
                  value={editNode.type}
                  onChange={(e) => setEditNode({ ...editNode, type: e.target.value })}
                  size="small"
                  sx={{
                    '& .MuiOutlinedInput-root': {
                      '&:hover fieldset': {
                        borderColor: 'primary.main',
                      },
                    },
                  }}
                />
              </Grid>
            </Grid>
          </Box>
        </DialogContent>
        <DialogActions>
          <Button 
            onClick={handleCloseDialog} 
            size="small"
            sx={{
              color: 'text.secondary',
              '&:hover': {
                backgroundColor: 'action.hover',
              },
            }}
          >
            取消
          </Button>
          <Button 
            variant="contained" 
            onClick={handleSave}
            disabled={loading}
            size="small"
            sx={{
              px: 3,
              boxShadow: 'none',
              '&:hover': {
                boxShadow: 'none',
              },
            }}
          >
            保存
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};

export default Nodes;
